import React from 'react';
import styles from './legacyField.module.css';

export interface LegacyCodeSuffixProps {
  value: string;
  shortLabel?: string;
  testId?: string;
}

/** Yellow «Mã cũ:» suffix — parity `legacy-id-field.md` lookup display. */
export const LegacyCodeSuffix: React.FC<LegacyCodeSuffixProps> = ({
  value,
  shortLabel = 'Mã cũ:',
  testId = 'legacy-code-suffix',
}) => {
  const trimmed = value?.trim();
  if (!trimmed) return null;
  return (
    <span className={styles.legacyCodeSuffix} data-testid={testId}>
      {shortLabel} {trimmed}
    </span>
  );
};
