import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  Button,
  Input,
  Modal,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionStageDto } from '../../../services/sx/models';
import { congDoanPageLabels as labels } from '../../../constants/congDoanPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { openListRowMenu } from '../../../utils/openListRowMenu';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../../../components/voucher-list';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { LegacyCodeSuffix } from '../../../components/legacy/LegacyCodeSuffix';
import legacyStyles from '../../../components/legacy/legacyField.module.css';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { useMesCongDoanPermissions } from '../../../hooks/useMesPermissions';
import { CatalogDocumentHistory } from '../../../components/catalog';
import { mesDocumentTypes } from '../../../config/documentHistoryClients';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-cong-doan';
const PAGE_ID = 'sx-cong-doan';
const CATALOG_KIND = LIST_UI_SCHEMA_KIND.mesProductionStage;
const showSchemaConfig = true;

type ModalMode = 'create' | 'edit' | 'view';

const emptyStage = { code: '', name: '', sequenceNo: 1, isActive: true };

const CongDoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useMesCongDoanPermissions();
  const [reloadKey, setReloadKey] = useState(0);
  const [stages, setStages] = useState<ProductionStageDto[]>([]);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('create');
  const [editing, setEditing] = useState<ProductionStageDto | null>(null);
  const [form, setForm] = useState(emptyStage);
  const [saving, setSaving] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: ProductionStageDto } | null>(
    null,
  );
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [historyOpen, setHistoryOpen] = useState(false);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [deleting, setDeleting] = useState(false);

  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);
  const readOnly = modalMode === 'view';

  const selection = useErpListSelection({
    rows: stages,
    totalCount: stages.length,
    page: 1,
    pageSize: Math.max(stages.length, 1),
    getRowId: r => r.id,
  });

  const anchor = selection.activeRow;

  const refresh = useCallback(() => {
    selection.clearActiveRow();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setReloadKey(k => k + 1);
    });
  }, [pulseSearch, searchDraft]);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getStages({ searchText: search || undefined })
        .then(data => {
          if (!cancelled) setStages(data);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, reloadKey, search]);

  const openCreate = useCallback(() => {
    setModalMode('create');
    setEditing(null);
    setForm(emptyStage);
    setModalOpen(true);
  }, []);

  const openStage = useCallback((s: ProductionStageDto, mode: 'edit' | 'view') => {
    setModalMode(mode);
    setEditing(s);
    setForm({ code: s.code, name: s.name, sequenceNo: s.sequenceNo, isActive: s.isActive });
    setModalOpen(true);
  }, []);

  const handleSave = async () => {
    if (readOnly) return;
    if (!form.code.trim() || !form.name.trim()) {
      dispatchAppToast(dispatch, { message: labels.requiredFields, type: 'error' });
      return;
    }
    setSaving(true);
    try {
      if (modalMode === 'edit' && editing) {
        await sxService.updateStage(editing.id, {
          name: form.name.trim(),
          sequenceNo: Number(form.sequenceNo),
          isActive: form.isActive,
        });
        dispatchAppToast(dispatch, { message: labels.updateSuccess, type: 'success' });
      } else {
        await sxService.createStage({
          code: form.code.trim(),
          name: form.name.trim(),
          sequenceNo: Number(form.sequenceNo),
        });
        dispatchAppToast(dispatch, { message: labels.createSuccess, type: 'success' });
      }
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') openStage(row, 'view');
      if (action === 'edit') openStage(row, 'edit');
    },
    [rowMenu?.row, openStage],
  );

  const modalTitle =
    modalMode === 'view'
      ? labels.modalViewTitle
      : modalMode === 'edit'
        ? labels.modalEditTitle
        : labels.modalAddTitle;

  const handleDelete = useCallback(async () => {
    if (!anchor) return;
    setDeleting(true);
    try {
      await sxService.deleteStage(anchor.id);
      dispatchAppToast(dispatch, { message: labels.deleteSuccess, type: 'success' });
      setDeleteOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.deleteError),
        type: 'error',
      });
    } finally {
      setDeleting(false);
    }
  }, [anchor, dispatch, refresh]);

  const catalogToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canAdd: perms.canCreate,
      onAdd: openCreate,
      showEdit: Boolean(anchor),
      showView: Boolean(anchor),
      canHistory: Boolean(anchor && perms.canRead),
      canDelete: Boolean(anchor && perms.canDelete),
      selectedCount: anchor ? 1 : 0,
      onEdit: () => anchor && openStage(anchor, 'edit'),
      onView: () => anchor && openStage(anchor, 'view'),
      onHistory: () => setHistoryOpen(true),
      onDelete: () => setDeleteOpen(true),
      ...(showSchemaConfig ? { onEditConfig: () => setShowSchemaEditor(true) } : {}),
    }),
    [refresh, openCreate, perms, anchor, openStage],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <div data-testid={`${TEST_ID}-field-search`}>
            <SearchTextInput
              label="Tìm kiếm"
              placeholder={labels.searchPlaceholder}
              value={searchDraft}
              onChange={setSearchDraft}
              onSearch={handleSearch}
              testId={`${TEST_ID}-search-text`}
            />
          </div>
        )}
      />
    ),
    [searchDraft, handleSearch, showTableLoading],
  );

  const listBody =
    !showTableLoading && stages.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th className={erp.colNo}>STT</th>
              <th>{labels.fieldCode}</th>
              <th>{labels.fieldName}</th>
              <th className={erp.colRight}>{labels.fieldSequence}</th>
              <th>{labels.fieldStatus}</th>
            </tr>
          </thead>
          <tbody>
            {stages.map((s, index) => (
              <tr
                key={s.id}
                data-testid={`${TEST_ID}-row-${s.id}`}
                className={selection.activeRow?.id === s.id ? erp.rowSelected : undefined}
                onDoubleClick={() => openStage(s, 'view')}
                onContextMenu={e =>
                  openListRowMenu(e, s, selection.selectActiveRow, setRowMenu)
                }
                onClick={e => {
                  if (e.ctrlKey || e.metaKey) {
                    openListRowMenu(e, s, selection.selectActiveRow, setRowMenu);
                  }
                }}
              >
                <td className={erp.colNo}>{index + 1}</td>
                <td>
                  <button
                    type="button"
                    className={erp.codeLink}
                    onClick={() => openStage(s, 'view')}
                  >
                    <code>{s.code}</code>
                  </button>
                </td>
                <td>{s.name}</td>
                <td className={erp.colRight}>{s.sequenceNo}</td>
                <td>
                  <span className={s.isActive ? erp.tagSuccess : erp.tagDefault}>
                    {s.isActive ? labels.statusActive : labels.statusInactive}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-catalog-list-page
      data-catalog-kind={CATALOG_KIND}
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.listTitle,
          titleIconClass: 'fas fa-cogs',
          pageId: PAGE_ID,
        }}
        catalogToolbar={catalogToolbar}
        listTitle={labels.listSubtitle}
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          stages.length > 0 ? (
            <div className={erp.paginationRow}>
              <span className={erp.totalCount}>Tổng: {stages.length} công đoạn</span>
            </div>
          ) : undefined
        }
        modals={
          <>
            {showSchemaConfig ? (
              <ListUiSchemaEditorModal
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                isOpen={showSchemaEditor}
                onClose={() => setShowSchemaEditor(false)}
                onSaved={() => refresh()}
                sampleRow={stages[0] as unknown as Record<string, unknown>}
              />
            ) : null}
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView={perms.canRead}
              showEdit={perms.canUpdate}
            />
            {anchor ? (
              <CatalogDocumentHistory
                testIdPrefix={TEST_ID}
                documentType={mesDocumentTypes.productionStage}
                documentId={anchor.id}
                documentCode={anchor.code}
                variant="inline"
                isOpen={historyOpen}
                onClose={() => setHistoryOpen(false)}
              />
            ) : null}
            <Modal
              isOpen={deleteOpen}
              onClose={() => !deleting && setDeleteOpen(false)}
              title="Xóa công đoạn"
            >
              <p>{labels.deleteConfirm}</p>
              {anchor ? <p><strong>{anchor.code}</strong></p> : null}
              <div className={erp.modalActions}>
                <Button variant="secondary" onClick={() => setDeleteOpen(false)} disabled={deleting}>
                  Hủy
                </Button>
                <Button variant="danger" onClick={handleDelete} loading={deleting}>
                  Xóa
                </Button>
              </div>
            </Modal>
            <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle}>
              <div className={erp.modalBody}>
                <div className={erp.field}>
                  <label className={erp.label}>{labels.fieldCode} *</label>
                  <div className={legacyStyles.codeFieldRow}>
                    <Input
                      value={form.code}
                      onChange={e => setForm(p => ({ ...p, code: e.target.value }))}
                      disabled={modalMode !== 'create'}
                      readOnly={readOnly}
                    />
                    {editing?.legacyCode ? (
                      <LegacyCodeSuffix
                        value={editing.legacyCode}
                        testId={`${TEST_ID}-legacy-code`}
                      />
                    ) : null}
                  </div>
                </div>
                <div className={erp.field}>
                  <label className={erp.label}>{labels.fieldName} *</label>
                  <Input
                    value={form.name}
                    onChange={e => setForm(p => ({ ...p, name: e.target.value }))}
                    readOnly={readOnly}
                  />
                </div>
                <div className={erp.field}>
                  <label className={erp.label}>{labels.fieldSequence}</label>
                  <Input
                    type="number"
                    min={1}
                    value={String(form.sequenceNo)}
                    onChange={e => setForm(p => ({ ...p, sequenceNo: Number(e.target.value) }))}
                    readOnly={readOnly}
                  />
                </div>
                {modalMode === 'edit' && (
                  <div className={erp.field}>
                    <label className={erp.label}>{labels.fieldStatus}</label>
                    <select
                      value={form.isActive ? 'true' : 'false'}
                      onChange={e =>
                        setForm(p => ({ ...p, isActive: e.target.value === 'true' }))
                      }
                    >
                      <option value="true">{labels.statusActive}</option>
                      <option value="false">{labels.statusInactive}</option>
                    </select>
                  </div>
                )}
                {modalMode === 'view' && (
                  <div className={erp.field}>
                    <label className={erp.label}>{labels.fieldStatus}</label>
                    <Input
                      value={form.isActive ? labels.statusActive : labels.statusInactive}
                      readOnly
                    />
                  </div>
                )}
              </div>
              <div className={erp.modalActions}>
                {editing && perms.canRead ? (
                  <CatalogDocumentHistory
                    testIdPrefix={`${TEST_ID}-modal`}
                    documentType={mesDocumentTypes.productionStage}
                    documentId={editing.id}
                    documentCode={editing.code}
                  />
                ) : null}
                <Button variant="secondary" onClick={() => setModalOpen(false)}>
                  {readOnly ? 'Đóng' : 'Huỷ'}
                </Button>
                {!readOnly &&
                (modalMode === 'create' ? perms.canCreate : perms.canUpdate) ? (
                  <Button variant="primary" onClick={handleSave} disabled={saving}>
                    {saving ? 'Đang lưu...' : 'Lưu'}
                  </Button>
                ) : null}
              </div>
            </Modal>
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default CongDoanPage;
